function solve(nums: number[]): number {
    const N = nums.length;

    // Step 0: Sort nums to get S
    // Create a copy so we don't modify the input array
    const S = [...nums].sort((a, b) => a - b);

    // Step 1 & 2: Find all divisors k of N
    const divisors: number[] = [];
    for (let k = 1; k * k <= N; k++) {
        if (N % k === 0) {
            divisors.push(k);
            if (k * k !== N) {
                divisors.push(N / k);
            }
        }
    }

    let totalSum = 0;

    // Step 3: Iterate over divisors k
    for (const k of divisors) {
        let isSortable = true;

        // Iterate through blocks i = 0 to N/k - 1
        const M = N / k;
        for (let i = 0; i < M; i++) {
            const L = i * k; // Start index of the block in nums and S

            // Check if A_i (nums[L...L+k-1]) is a cyclic permutation of S_i (S[L...L+k-1])

            let foundRotation = false;

            // Check k possible cyclic shifts (j = starting index in S_i, equivalent to left shift)
            // j is the rotation offset applied to S_i.
            for (let j = 0; j < k; j++) { 
                let matches = true;

                // Check if A_i matches the sequence generated by starting S_i at index j
                for (let l = 0; l < k; l++) {
                    // The element at index l in the rotated sequence R_j comes from S[L + (j + l) % k]
                    // L + (j + l) % k calculates the absolute index in S.
                    const S_i_l = S[L + (j + l) % k]; 
                    const A_i_l = nums[L + l];         

                    if (S_i_l !== A_i_l) {
                        matches = false;
                        break;
                    }
                }

                if (matches) {
                    foundRotation = true;
                    break;
                }
            }

            if (!foundRotation) {
                isSortable = false;
                break; // Move to the next divisor k
            }
        }

        if (isSortable) {
            totalSum += k;
        }
    }

    return totalSum;
}
